import React, { useState } from "react";
import { motion } from "framer-motion";
import { GitHub, LinkedinIcon, Mail, Moon, Sun } from "lucide-react";

export default function App() {
  const [theme, setTheme] = useState("dark");

  const toggleTheme = () => setTheme(theme === "dark" ? "light" : "dark");

  return (
    <div
      className={`${
        theme === "dark"
          ? "bg-gradient-to-br from-black via-gray-900 to-black text-white"
          : "bg-gradient-to-br from-gray-100 via-white to-gray-200 text-gray-900"
      } min-h-screen transition-all duration-500`}
    >
      <Navbar theme={theme} toggleTheme={toggleTheme} />
      <Hero theme={theme} />
      <Stats />
      <Experience theme={theme} />
      <Projects theme={theme} />
      <Contact theme={theme} />
      <Footer />
    </div>
  );
}

// NAVBAR
function Navbar({ theme, toggleTheme }) {
  return (
    <div className="sticky top-0 z-50 backdrop-blur-xl bg-white/5 border-b border-white/10">
      <div className="max-w-7xl mx-auto flex justify-between items-center px-6 py-4">
        <h1 className="font-bold text-xl tracking-widest">Muhammad Kashif</h1>

        <div className="hidden md:flex gap-8">
          {["Experience", "Projects", "Contact"].map((item) => (
            <a
              key={item}
              href={`#${item.toLowerCase()}`}
              className="relative group"
            >
              {item}
              <span className="absolute left-0 -bottom-1 w-0 h-[2px] bg-blue-500 group-hover:w-full transition-all" />
            </a>
          ))}
        </div>

        <button
          onClick={toggleTheme}
          className="p-2 rounded-xl border border-white/20 hover:bg-white/10"
        >
          {theme === "dark" ? <Sun size={18} /> : <Moon size={18} />}
        </button>
      </div>
    </div>
  );
}

// HERO
function Hero({ theme }) {
  return (
    <div className="text-center py-32 px-6">
      <motion.h1
        initial={{ opacity: 0, y: 50 }}
        animate={{ opacity: 1, y: 0 }}
        className="text-6xl md:text-7xl font-bold"
      >
        Muhammad Kashif
      </motion.h1>

      <motion.p
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.5 }}
        className="mt-6 text-xl text-gray-400"
      >
        Full Stack Engineer • Real-Time Systems • Mapping Specialist
      </motion.p>

      <div className="mt-10 flex justify-center gap-4">
        <a href="#projects">
          <button className="px-6 py-3 bg-blue-600 rounded-xl hover:scale-105 transition">
            View Projects
          </button>
        </a>

        <a href="#contact">
          <button className="px-6 py-3 border border-white/20 rounded-xl hover:bg-white/10 transition">
            Hire Me
          </button>
        </a>
      </div>

      <div className="flex justify-center gap-6 mt-8">
        <IconBtn icon={<GitHub />} />
        <IconBtn icon={<LinkedinIcon />} />
        <IconBtn icon={<Mail />} />
      </div>
    </div>
  );
}

function IconBtn({ icon }) {
  return (
    <div className="p-3 rounded-xl border border-white/20 hover:bg-white/10 cursor-pointer transition">
      {icon}
    </div>
  );
}

// STATS SECTION (NEW PREMIUM ADDITION)
function Stats() {
  const stats = [
    { label: "Years Experience", value: "3+" },
    { label: "Projects", value: "15+" },
    { label: "Technologies", value: "10+" },
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-5xl mx-auto py-16 px-6">
      {stats.map((s, i) => (
        <motion.div
          key={i}
          whileHover={{ scale: 1.05 }}
          className="p-8 rounded-2xl backdrop-blur-xl bg-white/5 border border-white/10 text-center"
        >
          <h2 className="text-3xl font-bold text-blue-400">{s.value}</h2>
          <p className="text-gray-400 mt-2">{s.label}</p>
        </motion.div>
      ))}
    </div>
  );
}

// EXPERIENCE
function Experience({ theme }) {
  return (
    <div id="experience" className="py-24 px-6">
      <h2 className="text-4xl font-bold text-center mb-16">Experience</h2>

      <div className="grid md:grid-cols-2 gap-8 max-w-6xl mx-auto">
        <Card
          title="Real-Time Systems"
          desc="Built air traffic monitoring systems with live WebSocket data and map visualization."
        />
        <Card
          title="Full Stack Development"
          desc="Developed scalable apps with React, Node.js, and MongoDB."
        />
      </div>
    </div>
  );
}

function Card({ title, desc }) {
  return (
    <motion.div
      whileHover={{ scale: 1.05 }}
      className="p-8 rounded-3xl backdrop-blur-xl bg-white/5 border border-white/10"
    >
      <h3 className="text-2xl font-semibold mb-4">{title}</h3>
      <p className="text-gray-400">{desc}</p>
    </motion.div>
  );
}

// PROJECTS
function Projects() {
  const projects = [
    "Air Traffic App",
    "Map Drawing Tool",
    "Sensor Dashboard",
  ];

  return (
    <div id="projects" className="py-24 px-6">
      <h2 className="text-4xl font-bold text-center mb-16">Projects</h2>

      <div className="grid md:grid-cols-3 gap-8 max-w-6xl mx-auto">
        {projects.map((p, i) => (
          <motion.div
            key={i}
            whileHover={{ scale: 1.05 }}
            className="p-8 rounded-3xl backdrop-blur-xl bg-white/5 border border-white/10"
          >
            <h3 className="text-xl font-semibold mb-3">{p}</h3>
            <button className="mt-4 text-blue-400 hover:underline">
              View Details →
            </button>
          </motion.div>
        ))}
      </div>
    </div>
  );
}

// CONTACT
function Contact() {
  return (
    <div id="contact" className="py-24 px-6">
      <h2 className="text-4xl font-bold text-center mb-12">Contact</h2>

      <div className="max-w-xl mx-auto p-10 rounded-2xl backdrop-blur-xl bg-white/5 border border-white/10">
        <input placeholder="Name" className="input" />
        <input placeholder="Email" className="input" />
        <textarea placeholder="Message" className="input" />

        <button className="w-full mt-4 bg-blue-600 py-3 rounded-xl hover:scale-105 transition">
          Send Message
        </button>
      </div>
    </div>
  );
}

// FOOTER
function Footer() {
  return (
    <div className="text-center py-8 text-gray-500 text-sm">
      © 2026 Muhammad Kashif — All rights reserved
    </div>
  );
